# phytron.proto
# StreamDevice protocol definitions for Phytron MCC-1 MINI-W-ETH
# TCP/IP communication on port 22222
#
# NOTE:
# Command and response strings are initial scaffold assumptions and may
# need adjustment to match the exact MCC-1 firmware command set.

Terminator = CR LF;
ReplyTimeout = 1000;
ReadTimeout = 1000;
WriteTimeout = 1000;
LockTimeout = 5000;
ExtraInput = Ignore;

# Read current position readback.
getPos {
    out "POS?";
    in "%f";
}

# Read configured speed readback.
getSpeed {
    out "SPEED?";
    in "%f";
}

# Move in positive direction.
# This is implemented as a command-only action.
movePlus {
    out "MOVE_PLUS";
}

# Move in negative direction.
# This is implemented as a command-only action.
moveMinus {
    out "MOVE_MINUS";
}

# Stop motion.
# Included from context as a useful initial control.
stopMove {
    out "STOP";
}
